import static org.junit.jupiter.api.Assertions.*;
import org.apache.commons.csv.CSVFormat;
import org.junit.jupiter.api.Test;

class CSVFormatTest {

    @Test
    void testGetTrimDefaultFalse() {
        CSVFormat format = CSVFormat.DEFAULT;
        assertFalse(format.getTrim());
    }

    @Test
    void testGetTrimTrue() {
        CSVFormat formatTrimmed = CSVFormat.DEFAULT.withTrim(true);
        assertTrue(formatTrimmed.getTrim());
    }

    @Test
    void testGetTrimFalseExplicit() {
        CSVFormat formatNotTrimmed = CSVFormat.DEFAULT.withTrim(false);
        assertFalse(formatNotTrimmed.getTrim());
    }
}
